/*
 * BCD Validation and Don't-Care Condition Handler
 * Demonstrates identification and handling of don't-care conditions
 * in digital logic design
 * 
 * Don't-care conditions occur in BCD because:
 * - BCD uses 4 bits to represent decimal digits 0-9
 * - Combinations 1010 to 1111 (10-15) are invalid/unused
 * - These can be treated as X (either 0 or 1) for optimization
 */

#include <stdio.h>
#include <stdbool.h>

// BCD digit validation constants
#define BCD_MIN 0
#define BCD_MAX 9
#define DONT_CARE_START 10
#define DONT_CARE_END 15

/*
 * Structure to represent a 4-bit BCD input with don't-care info
 */
typedef struct {
 unsigned int A:1; // MSB (8)
 unsigned int B:1; // (4)
 unsigned int C:1; // (2)
 unsigned int D:1; // LSB (1)
} BCDInput;

/*
 * Enumeration for input classification
 */
typedef enum {
 VALID_BCD,
 DONT_CARE,
 INVALID
} InputType;

/*
 * Convert BCDInput to integer value (0-15)
 */
int bcd_to_int(BCDInput input) {
 return (input.A << 3) | (input.B << 2) | (input.C << 1) | input.D;
}

/*
 * Classify input: valid BCD, don't-care, or invalid
 */
InputType classify_input(BCDInput input) {
 int value = bcd_to_int(input);

 if (value >= BCD_MIN && value <= BCD_MAX) {
 return VALID_BCD;
 } else if (value >= DONT_CARE_START && value <= DONT_CARE_END) {
 return DONT_CARE;
 }
 return INVALID;
}

/*
 * Check if segment should be ON for given input
 * Using simplified expression: F = A + C + B'D' + BD
 * Don't-care conditions can output either 0 or 1
 */
int evaluate_segment_a(BCDInput input) {
 // F = A + C + B'D' + BD
 int term_A = input.A;
 int term_C = input.C;
 int term_BnDn = (!input.B) && (!input.D); // B' D'
 int term_BD = input.B && input.D; // B D

 int result = term_A || term_C || term_BnDn || term_BD;
 return result;
}

/*
 * For don't-care inputs, decide optimal output value
 * This demonstrates the flexibility of don't-care conditions
 */
int optimize_dont_care(BCDInput input, bool use_as_one) {
 if (use_as_one) {
 // Treat don't-care as 1 - helps form larger groups
 return 1;
 } else {
 // Treat don't-care as 0 - ignore for this grouping
 return 0;
 }
}

/*
 * Display K-Map representation with don't-cares
 */
void display_kmap(void) {
 printf("\nK-Map for Segment 'a' (F = A + C + B'D' + BD):\n");
 printf("AB \\ CD | 00 | 01 | 11 | 10 |\n");
 printf("------|------|------|------|------|\n");
 printf(" 00 | 1 | 0 | 1 | 1 | (m0,m1,m2,m3)\n");
 printf(" 01 | 0 | 1 | 1 | 1 | (m4,m5,m6,m7)\n");
 printf(" 11 | X | X | X | X | (m12-m15: don't-cares)\n");
 printf(" 10 | 1 | 1 | X | X | (m8-m11: m8,m9=1; m10,m11=X)\n");

 printf("\nGrouping strategy:\n");
 printf(" Group 1: Corners (m0,m2,m8,m10+X) -> B'D'\n");
 printf(" Group 2: 8-cell (m2,m3,m6,m7 + X m10-m15) -> C\n");
 printf(" Group 3: 4-cell (m5,m7,m13+X,m15+X) -> BD\n");
 printf(" Group 4: 2-cell (m8,m9 + X m10-m15) -> A\n");
}

/*
 * Test all 16 possible 4-bit input combinations
 */
void test_all_inputs(void) {
 BCDInput input;

 printf("BCD to 7-Segment - Segment 'a' Decoder\n");
 printf("========================================\n");
 printf("%-8s %-6s %-8s %-8s %s\n", "Value", "Binary", "Type", "Segment", "Notes");
 printf("----------------------------------------\n");

 for (int i = 0; i < 16; i++) {
 input.D = i & 1;
 input.C = (i >> 1) & 1;
 input.B = (i >> 2) & 1;
 input.A = (i >> 3) & 1;

 InputType type = classify_input(input);
 int segment = evaluate_segment_a(input);

 char *type_str;
 char *notes = "";

 switch (type) {
 case VALID_BCD:
 type_str = "Valid BCD";
 break;
 case DONT_CARE:
 type_str = "Don't-care";
 notes = "(can be 0 or 1)";
 break;
 default:
 type_str = "Invalid";
 }

 printf("%-8d %c%c%c%c %-8s %-8d %s\n", 
 i, 
 input.A + '0', input.B + '0', input.C + '0', input.D + '0',
 type_str, 
 segment,
 notes);
 }
}

/*
 * Demonstrate circuit complexity comparison
 */
void print_complexity_comparison(void) {
 printf("\nCircuit Complexity Comparison:\n");
 printf("===============================\n");

 printf("\nWithout Don't-Care Optimization:\n");
 printf(" Expression: F = A'C'D + A'BC + AB'D + ABC' + ABC + A'C'D'\n");
 printf(" Gates needed:\n");
 printf(" - 3-input AND gates: 4\n");
 printf(" - 2-input AND gates: 2\n");
 printf(" - NOT gates: 4\n");
 printf(" - 6-input OR gate: 1\n");
 printf(" Total gates: 11\n");

 printf("\nWith Don't-Care Optimization:\n");
 printf(" Expression: F = A + C + B'D' + BD\n");
 printf(" Gates needed:\n");
 printf(" - 2-input AND gates: 1 (for BD)\n");
 printf(" - NOT gates: 2 (for B', D')\n");
 printf(" - 4-input OR gate: 1\n");
 printf(" Total gates: 4\n");

 printf("\nReduction: 64%% fewer gates!\n");
}

int main(void) {
 printf("Don't-Care Conditions in Digital Logic Design\n");
 printf("==============================================\n");

 test_all_inputs();
 display_kmap();
 print_complexity_comparison();

 // Demonstrate don't-care flexibility
 printf("\nDon't-Care Flexibility:\n");
 printf("-----------------------\n");
 printf("The same don't-care can be used differently in different groups:\n");
 printf(" - Input 10 (1010): used as 1 for B'D' term, as 0 for BD term\n");
 printf(" - Input 14 (1110): used as 1 for C term, ignored for others\n");
 printf("This flexibility is the key advantage of don't-care conditions!\n");

 return 0;
}
